import React, { useState } from "react";
// import Lightbox from "react-image-lightbox";
// import "react-image-lightbox/style.css";

const images = [
  { src: "images/IMG_0422.JPG.jpeg", title: "Engagement photo" },
  { src: "images/DSC07516.JPG.jpeg", title: "Couple photo" },
  { src: "images/DSC07488.JPG.jpeg", title: "Family photo" },
];

const Gallery = () => {
  const [photoIndex, setPhotoIndex] = useState(0);
  const [isOpen, setIsOpen] = useState(false);

  return (
    <section id="gallery" className="card">
      <h3>Photo Gallery</h3>
      <div className="gallery">
        {images.map((img, index) => (
          <img
            key={index}
            src={img.src}
            alt={img.title}
            onClick={() => { setPhotoIndex(index); setIsOpen(true); }}
            style={{ cursor: "pointer", width: "150px", margin: "10px" }}
          />
        ))}
      </div>

      {isOpen && (
        <Lightbox
          mainSrc={images[photoIndex].src}
          nextSrc={images[(photoIndex + 1) % images.length].src}
          prevSrc={images[(photoIndex + images.length - 1) % images.length].src}
          onCloseRequest={() => setIsOpen(false)}
          onMovePrevRequest={() => setPhotoIndex((photoIndex + images.length - 1) % images.length)}
          onMoveNextRequest={() => setPhotoIndex((photoIndex + 1) % images.length)}
        />
      )}
    </section>
  );
};

export default Gallery;
